package com.example.biometricauth;

import android.content.Context;

import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;
import androidx.biometric.BiometricManager;
import androidx.biometric.BiometricPrompt;
import androidx.core.content.ContextCompat;

import java.util.concurrent.Executor;

public class BiometricAuthHelper {

    public interface AuthenticationListener {
        void onAuthenticationSucceeded();
        void onAuthenticationError(String error);
        void onAuthenticationFailed();
    }

    private final AppCompatActivity activity;
    private final AuthenticationListener listener;

    public BiometricAuthHelper(@NonNull AppCompatActivity activity,
                               @NonNull AuthenticationListener listener) {
        this.activity = activity;
        this.listener = listener;
    }

    public boolean canAuthenticate() {
        BiometricManager biometricManager = BiometricManager.from(activity);
        int result = biometricManager.canAuthenticate(
                BiometricManager.Authenticators.BIOMETRIC_STRONG
                        | BiometricManager.Authenticators.BIOMETRIC_WEAK
        );
        return result == BiometricManager.BIOMETRIC_SUCCESS;
    }

    public void authenticate(String title, String subtitle, String negativeButtonText) {
        Executor executor = ContextCompat.getMainExecutor(activity);
        BiometricPrompt biometricPrompt = new BiometricPrompt(activity, executor,
                new BiometricPrompt.AuthenticationCallback() {
                    @Override
                    public void onAuthenticationError(int errorCode, @NonNull CharSequence errString) {
                        super.onAuthenticationError(errorCode, errString);
                        listener.onAuthenticationError(errString.toString());
                    }

                    @Override
                    public void onAuthenticationSucceeded(@NonNull BiometricPrompt.AuthenticationResult result) {
                        super.onAuthenticationSucceeded(result);
                        listener.onAuthenticationSucceeded();
                    }

                    @Override
                    public void onAuthenticationFailed() {
                        super.onAuthenticationFailed();
                        listener.onAuthenticationFailed();
                    }
                });

        BiometricPrompt.PromptInfo promptInfo = new BiometricPrompt.PromptInfo.Builder()
                .setTitle(title)
                .setSubtitle(subtitle)
                .setAllowedAuthenticators(
                        BiometricManager.Authenticators.BIOMETRIC_STRONG
                                | BiometricManager.Authenticators.BIOMETRIC_WEAK
                )
                .setNegativeButtonText(negativeButtonText)
                .build();

        biometricPrompt.authenticate(promptInfo);
    }
}

package com.example.biometricauth;

import android.content.Intent;
import android.os.Bundle;

import androidx.appcompat.app.AppCompatActivity;

public class SplashActivity extends AppCompatActivity implements BiometricAuthHelper.AuthenticationListener {

    private BiometricAuthHelper biometricAuthHelper;
    private boolean promptShown = false;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        if (PrefsManager.isLoggedIn(this)) {
            navigateToHome();
            return;
        }

        if (PrefsManager.isBiometricEnabled(this)) {
            biometricAuthHelper = new BiometricAuthHelper(this, this);
            if (biometricAuthHelper.canAuthenticate()) {
                showBiometricPrompt();
            } else {
                navigateToLogin();
            }
        } else {
            navigateToLogin();
        }
    }

    @Override
    protected void onResume() {
        super.onResume();
        if (!promptShown && PrefsManager.isBiometricEnabled(this) && !PrefsManager.isLoggedIn(this)) {
            biometricAuthHelper = new BiometricAuthHelper(this, this);
            if (biometricAuthHelper.canAuthenticate()) {
                showBiometricPrompt();
            }
        }
    }

    private void showBiometricPrompt() {
        promptShown = true;
        biometricAuthHelper.authenticate(
                "Unlock App",
                "Use your fingerprint to continue",
                "Use Password"
        );
    }

    private void navigateToLogin() {
        startActivity(new Intent(this, LoginActivity.class));
        finish();
    }

    private void navigateToHome() {
        startActivity(new Intent(this, HomeActivity.class));
        finish();
    }

    @Override
    public void onAuthenticationSucceeded() {
        PrefsManager.setLoggedIn(this, true);
        navigateToHome();
    }

    @Override
    public void onAuthenticationError(String error) {
        navigateToLogin();
    }

    @Override
    public void onAuthenticationFailed() {
    }
}

package com.example.biometricauth;

import android.content.Intent;
import android.os.Bundle;
import android.text.TextUtils;
import android.widget.Button;
import android.widget.CheckBox;
import android.widget.EditText;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

public class LoginActivity extends AppCompatActivity {

    private EditText etUsername;
    private EditText etPassword;
    private CheckBox cbEnableBiometric;
    private Button btnLogin;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);

        etUsername = findViewById(R.id.etUsername);
        etPassword = findViewById(R.id.etPassword);
        cbEnableBiometric = findViewById(R.id.cbEnableBiometric);
        btnLogin = findViewById(R.id.btnLogin);

        cbEnableBiometric.setChecked(PrefsManager.isBiometricEnabled(this));

        btnLogin.setOnClickListener(v -> handleLogin());
    }

    private void handleLogin() {
        String username = etUsername.getText() != null ? etUsername.getText().toString().trim() : "";
        String password = etPassword.getText() != null ? etPassword.getText().toString().trim() : "";

        if (TextUtils.isEmpty(username) || TextUtils.isEmpty(password)) {
            Toast.makeText(this, "Enter username and password", Toast.LENGTH_SHORT).show();
            return;
        }

        if (isValidCredentials(username, password)) {
            if (cbEnableBiometric.isChecked()) {
                BiometricAuthHelper helper = new BiometricAuthHelper(this, new BiometricAuthHelper.AuthenticationListener() {
                    @Override
                    public void onAuthenticationSucceeded() {
                        PrefsManager.setBiometricEnabled(LoginActivity.this, true);
                        completeLogin();
                    }

                    @Override
                    public void onAuthenticationError(String error) {
                        Toast.makeText(LoginActivity.this, "Biometric setup canceled", Toast.LENGTH_SHORT).show();
                        PrefsManager.setBiometricEnabled(LoginActivity.this, false);
                        completeLogin();
                    }

                    @Override
                    public void onAuthenticationFailed() {
                        Toast.makeText(LoginActivity.this, "Fingerprint not recognized", Toast.LENGTH_SHORT).show();
                    }
                });

                if (helper.canAuthenticate()) {
                    helper.authenticate(
                            "Enable Biometric Login",
                            "Confirm your fingerprint to enable biometric login",
                            "Cancel"
                    );
                } else {
                    Toast.makeText(this, "Biometric authentication is not available", Toast.LENGTH_SHORT).show();
                    PrefsManager.setBiometricEnabled(this, false);
                    completeLogin();
                }
            } else {
                PrefsManager.setBiometricEnabled(this, false);
                completeLogin();
            }
        } else {
            Toast.makeText(this, "Invalid username or password", Toast.LENGTH_SHORT).show();
        }
    }

    private boolean isValidCredentials(String username, String password) {
        return "user".equals(username) && "password".equals(password);
    }

    private void completeLogin() {
        PrefsManager.setLoggedIn(this, true);
        startActivity(new Intent(this, HomeActivity.class));
        finish();
    }
}

package com.example.biometricauth;

import android.content.Intent;
import android.os.Bundle;
import android.widget.Button;

import androidx.appcompat.app.AppCompatActivity;

public class HomeActivity extends AppCompatActivity {

    private Button btnLogout;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_home);

        btnLogout = findViewById(R.id.btnLogout);
        btnLogout.setOnClickListener(v -> {
            PrefsManager.clearSession(this);
            startActivity(new Intent(this, LoginActivity.class));
            finish();
        });
    }
}